/**
 * Fast food + gas / c-store batch (10 profiles). Writes server/db/profiles_v13/*.json and upserts DB.
 * Usage (repo root): DATABASE_URL="…" node server/db/install_v13.mjs
 */
import { writeFileSync, mkdirSync } from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";
import pg from "pg";
const { Pool } = pg;
const __dirname = dirname(fileURLToPath(import.meta.url));
if (!process.env.DATABASE_URL) {
  console.error("Set DATABASE_URL");
  process.exit(1);
}
const pool = new Pool({ connectionString: process.env.DATABASE_URL, ssl: { rejectUnauthorized: false } });
const encoded = [
["7-eleven",""],
["chipotle",""],
["circle-k",""],
["darden-restaurants",""],
["dominos",""],
["pilot-flying-j",""],
["subway",""],
["waffle-house",""],
["wendys",""],
["yum-brands",""]
];
async function main() {
  mkdirSync(join(__dirname, "profiles_v13"), { recursive: true });
  for (const [slug, b64] of encoded) {
    const j = Buffer.from(b64, "base64").toString("utf8");
    const p = JSON.parse(j);
    writeFileSync(join(__dirname, "profiles_v13", slug + ".json"), JSON.stringify(p, null, 2));
    await pool.query(
      `INSERT INTO incumbent_profiles (brand_slug, brand_name, parent_company, ultimate_parent, overall_concern_level, profile_type, profile_json)
       VALUES ($1,$2,$3,$4,$5,$6,$7)
       ON CONFLICT (brand_slug) DO UPDATE SET
         brand_name=EXCLUDED.brand_name, parent_company=EXCLUDED.parent_company,
         ultimate_parent=EXCLUDED.ultimate_parent, overall_concern_level=EXCLUDED.overall_concern_level,
         profile_type=EXCLUDED.profile_type, profile_json=EXCLUDED.profile_json, updated_at=NOW()`,
      [slug, p.brand_name, p.parent_company, p.ultimate_parent,
       p.overall_concern_level, p.profile_type || "database", j]
    );
    console.log("upserted", slug);
  }
  await pool.end();
  console.log("Done.", encoded.length, "profiles.");
}
main().catch(err => { console.error(err); process.exit(1); });
